```jsx live-dev
const App = () => {
  const [page, setPage] = useState(1);
  const pageSize = 3;

  const columns = [
    { id: 'name', header: 'Name', accessor: (row) => row.name },
    { id: 'role', header: 'Role', accessor: (row) => row.role },
  ];

  const allRows = Array.from({ length: 10 }, (_, i) => ({
    id: String(i + 1),
    name: `User ${i + 1}`,
    role: i % 2 === 0 ? 'Admin' : 'User',
  }));

  const totalPages = Math.ceil(allRows.length / pageSize);
  const rows = allRows.slice((page - 1) * pageSize, page * pageSize);

  return (
    <DataTable
      columns={columns}
      rows={rows}
      footer={
        <Stack direction="row" justify="space-between" align="center" width="full" px="400" py="300">
          <Text fontSize="sm">
            Showing {(page - 1) * pageSize + 1}-{Math.min(page * pageSize, allRows.length)} of {allRows.length}
          </Text>
          <Stack direction="row" gap="200">
            <Button
              size="md"
              colorPalette="primary"
              variant="outline"
              onPress={() => setPage((p) => Math.max(1, p - 1))}
              isDisabled={page === 1}
            >
              Previous
            </Button>
            <Button
              size="md"
              variant="outline"
              colorPalette="primary"
              onPress={() => setPage((p) => Math.min(totalPages, p + 1))}
              isDisabled={page === totalPages}
            >
              Next
            </Button>
          </Stack>
        </Stack>
      }
    />
  );
}
```

